8460	  \label{lem:isProductOfDisjoint_mathlib}
8461	  \lean{TopCat.Sheaf.isProductOfDisjoint}
8462	  \mathlibok
8463	  \textit{Provided by Mathlib.}
8464	  For a sheaf \(F\) (valued in a category with products) on a topological space and two opens
8465	  \(U, V\) with \(U \sqcap V = \bot\) (disjoint), the sections over the union are the product
8466	  of the sections: \(F(U \sqcup V) \cong F(U) \times F(V)\). Iterated over a finite family,
8467	  this is the disjoint-union decomposition underlying Lemma~\ref{lem:pushPull_sigma_iso}.
8468	\end{lemma}
